const cves = $input.all().map(i => i.json);

const weekStart = new Date();
weekStart.setDate(weekStart.getDate() - 7);
const fmt = d => d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
const weekLabel = fmt(weekStart);
const today = fmt(new Date());

const hitlCves       = cves.filter(c => c.hitl_required);
const alertCves      = cves.filter(c => !c.hitl_required && c.exploitable_on_this_system && c.alert_sent);
const silentHighCves = cves.filter(c => !c.hitl_required && !c.exploitable_on_this_system);
const total = cves.length;

function cveRow(c) {
  const cvss = parseFloat(c.cvss_score) || 0;
  const color = cvss >= 9 ? '#b71c1c' : cvss >= 7 ? '#e65100' : '#1565c0';
  const patchCell = c.patch_available
    ? `<span style="color:#2e7d32">✓ ${c.fixed_version || 'patch available'}</span>`
    : `<span style="color:#b71c1c">✗ no patch</span>`;
  const kevBadge = c.kev_listed
    ? `<span style="background:#b71c1c;color:#fff;padding:1px 5px;border-radius:3px;font-size:11px;margin-left:4px">KEV</span>`
    : '';
  const hitlStatus = c.hitl_decision
    ? `<span style="color:#666;font-size:12px"> → ${c.hitl_decision}</span>`
    : '';
  return `<tr>
    <td style="padding:8px;border-bottom:1px solid #eee">${c.cve_id}${kevBadge}${hitlStatus}</td>
    <td style="padding:8px;border-bottom:1px solid #eee">${c.affected_software} ${c.affected_version || ''}</td>
    <td style="padding:8px;border-bottom:1px solid #eee;color:${color};font-weight:bold">${cvss.toFixed(1)}</td>
    <td style="padding:8px;border-bottom:1px solid #eee">${patchCell}</td>
    <td style="padding:8px;border-bottom:1px solid #eee;color:#555;font-size:12px">${(c.exploitability_reason || '—').substring(0, 120)}</td>
  </tr>`;
}

function section(title, color, rows) {
  if (!rows.length) return '';
  return `
    <h3 style="color:${color};margin:28px 0 8px;font-size:15px">${title} (${rows.length})</h3>
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <tr style="background:#f5f5f5">
        <th style="padding:8px;text-align:left">CVE</th>
        <th style="padding:8px;text-align:left">Software</th>
        <th style="padding:8px;text-align:left">CVSS</th>
        <th style="padding:8px;text-align:left">Patch</th>
        <th style="padding:8px;text-align:left">Reason</th>
      </tr>
      ${rows.map(cveRow).join('')}
    </table>`;
}

const emptyMsg = total === 0
  ? `<p style="color:#2e7d32;font-size:15px">✓ No CVEs detected this week. VPS appears clean.</p>`
  : '';

const subject = hitlCves.length > 0
  ? `VulnWatch: ${hitlCves.length} HITL decision(s) pending — week of ${weekLabel}`
  : alertCves.length > 0
  ? `VulnWatch: ${alertCves.length} exploitable CVE(s) this week — ${today}`
  : total > 0
  ? `VulnWatch Weekly: ${total} CVE(s) found, none exploitable — ${today}`
  : `VulnWatch Weekly: All clear — ${today}`;

const html = `<!DOCTYPE html>
<html>
<body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;color:#333">
  <div style="background:#1565c0;padding:16px 20px;border-radius:6px 6px 0 0">
    <h2 style="color:white;margin:0;font-size:18px">VulnWatch Weekly Digest</h2>
    <p style="color:#90caf9;margin:4px 0 0;font-size:13px">${weekLabel} &rarr; ${today}</p>
  </div>
  <div style="border:1px solid #ddd;border-top:none;padding:20px;border-radius:0 0 6px 6px">
    <table style="width:100%;text-align:center;margin-bottom:20px">
      <tr>
        <td style="padding:14px">
          <div style="font-size:32px;font-weight:bold;color:#1565c0">${total}</div>
          <div style="font-size:12px;color:#777;margin-top:2px">Total CVEs</div>
        </td>
        <td style="padding:14px">
          <div style="font-size:32px;font-weight:bold;color:#b71c1c">${hitlCves.length}</div>
          <div style="font-size:12px;color:#777;margin-top:2px">Needed Your Decision</div>
        </td>
        <td style="padding:14px">
          <div style="font-size:32px;font-weight:bold;color:#e65100">${alertCves.length}</div>
          <div style="font-size:12px;color:#777;margin-top:2px">Auto-Alerted</div>
        </td>
        <td style="padding:14px">
          <div style="font-size:32px;font-weight:bold;color:#2e7d32">${silentHighCves.length}</div>
          <div style="font-size:12px;color:#777;margin-top:2px">Non-Exploitable</div>
        </td>
      </tr>
    </table>
    ${emptyMsg}
    ${section('🚨 Required Your Decision (HITL)', '#b71c1c', hitlCves)}
    ${section('⚠️ Auto-Alerted — Exploitable on This System', '#e65100', alertCves)}
    ${section('✓ High CVSS — Not Exploitable on This Config', '#2e7d32', silentHighCves)}
    <p style="color:#bbb;font-size:11px;margin-top:28px;padding-top:12px;border-top:1px solid #eee">
      VulnWatch &nbsp;|&nbsp; Autonomous CVE Monitoring &nbsp;|&nbsp; All data stays on VPS
    </p>
  </div>
</body>
</html>`;

return [{ json: { html, subject, total, hitl_count: hitlCves.length, alert_count: alertCves.length } }];
